var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"우왁! 갑자기 땅이……!","JPN":"なっ、なんだ？　急に地面が……！","ENG":"Whoa! The ground...!","TWN":"嗚哇！地面突然……！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"저, 저기! 모래 폭풍이 다가오고 있어!","JPN":"あ、あれは！　砂嵐が来ているぞ！","ENG":"L-look! The sandstorm's closing in!","TWN":"那，那個！沙塵暴正在逼近！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"어, 어째서 이곳에 도시가? 시, 신기루?","JPN":"な、なぜここに都市が？　ま、幻か？","ENG":"H-how is there a city here? I-is it a mirage?","TWN":"這裡，怎麼會有城市？是，是海市蜃樓嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"분명 우린 사막 한가운데에 있었는데……?","JPN":"確か、砂漠のど真ん中にいたはずなんじゃ……？","ENG":"Weren't we in the middle of the desert...?","TWN":"我們明明在沙漠正中央……？"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"으, 으으!! 저기 침식체가 나타났다!!!","JPN":"お、おい！！　侵食体が現れたぞ！！","ENG":"U-um!! The C.O. has appeared!!!","TWN":"呃呃呃！！是那個侵蝕體！！！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_NULL","text":{"KOREA":"흐, 흐아아악!!! 도망, 도망쳐!!","JPN":"う、うわああっ！！！　逃げ、逃げろ！！","ENG":"G-geeze!!! RUN! Run for your lives!!","TWN":"哇，哇啊啊啊！！！大，大家快逃！！"},"stage":{"bg":"VARUNA_04_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_03"},{"id":"L30_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_NULL","text":{"KOREA":"저, 저게 도시를 삼켰다는 침식체? 커도 너무 크잖아!!!","JPN":"あ、あれが都市を飲み込んだ侵食体なのか？　なんて大きさなんだ！！！","ENG":"Th-that's the C.O. that swallowed an entire city? It's frickin' massive!!!","TWN":"那，那就是吞噬掉城市的侵蝕體？塊頭也太大！！！"},"stage":{"bg":"VARUNA_04_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_NULL","text":{"KOREA":"도시 밖에 모래 폭풍이 몰아치고 있다! 퇴로가 막혔어!","JPN":"都市の外側に砂嵐が来ているぞ！　退路が塞がれた！","ENG":"There's a sandstorm outside the city! Our escape route is blocked!","TWN":"城市外圍也有沙塵暴！我們現在退無可退！"},"stage":{"bg":"VARUNA_04_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이 모래 폭풍과 도시는 역시…….","JPN":"この砂嵐と都市はやはり……","ENG":"Just as I thought. The sandstorm and the city...","TWN":"這場沙塵暴和城市……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"침식체가 덧씌운 이면세계로부터 이 모든 게 생겨났다는 건가…….","JPN":"侵食体が上書きした裏世界から、すべてが生み出されたのか……","ENG":"The C.O. brought everything from the covered Counterside...","TWN":"果然都是從侵蝕體所在的異界中產生的嗎……"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"놈의 주의를 끌어야 합니다! 에스타크가 포격을 시작하기엔 시간이 모자라요!","JPN":"奴の注意を引かなければなりません！　エスタークが砲撃準備を完了するまで時間を稼ぐんです！","ENG":"We need to distract it! There isn't enough time for Estaque to start its bombardments!","TWN":"必須要吸引它的注意力！艾斯塔克炮擊需要時間！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L41_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"젠장! 서둘러라! 시간이 지체될수록 희생자가 발생하기 시작할 거다!","JPN":"くそっ！　急げ！　どんどん犠牲者が出始めるぞ！","ENG":"Dammit! Hurry! More casualties will occur the longer we delay!","TWN":"該死！動作快！時間拖得越久，犧牲者只會越多！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"지금은…… 에스타크의 화력이 통하길 바라는 수밖에.","JPN":"今は……エスタークの火力が有効であることを願うしかない。","ENG":"Right now... we can only hope that Estaque's firepower works on it.","TWN":"現在……只能冀望艾斯塔克的火力能奏效。"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"모두 무기를 들어라! 내가 앞에서 적의 공격을 받아내겠다!","JPN":"全員武器を取れ！　私が先頭で奴の攻撃を受け止める！","ENG":"All hands, ready your weapons! I will fend off the enemy's attack at the front!","TWN":"大家拿起武器！我負責在前面擋住敵人的攻擊！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아합이 포격을 시작할 때까지 버텨야 한다!","JPN":"アハブが砲撃を始めるまで持ちこたえるんだ！","ENG":"We must hold out until Ahab starts the bombarding!","TWN":"必須堅持到亞哈開始炮擊為止！"},"stage":{"bg":"CITY_DESERT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};